package com.example.kafkastreaming.service;

import java.time.Instant;
import java.util.UUID;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

@Service
public class EventProducer {

    private final KafkaTemplate<String, String> kafkaTemplate;

    @Value("${app.kafka.topic.events:events}")
    private String eventsTopic;

    public EventProducer(KafkaTemplate<String, String> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public void publishEvent(String payload) {
        String key = UUID.randomUUID().toString();
        String value = Instant.now().toString() + " | " + payload;
        kafkaTemplate.send(eventsTopic, key, value);
    }
}

package com.example.kafkastreaming.consumer;

import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.kafka.support.Acknowledgment;
import org.springframework.stereotype.Component;

@Component
public class EventConsumer {

    @KafkaListener(
            topics = "${app.kafka.topic.events:events}",
            groupId = "${app.kafka.consumer.group-id:event-streaming-platform}",
            containerFactory = "kafkaListenerContainerFactory"
    )
    public void onMessage(ConsumerRecord<String, String> record, Acknowledgment ack) {
        try {
            String key = record.key();
            String value = record.value();
            int partition = record.partition();
            long offset = record.offset();

            System.out.println("Consumed event: key=" + key + ", value=" + value + ", partition=" + partition + ", offset=" + offset);

            ack.acknowledge();
        } catch (Exception e) {
            throw e;
        }
    }
}

package com.example.kafkastreaming.web;

import com.example.kafkastreaming.service.EventProducer;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/events")
public class EventController {

    private final EventProducer producer;

    public EventController(EventProducer producer) {
        this.producer = producer;
    }

    @PostMapping
    public ResponseEntity<Void> publish(@RequestBody String payload) {
        producer.publishEvent(payload);
        return ResponseEntity.accepted().build();
    }
}

